const waitForE = async (timeout = 2000, interval = 50) => {
    const start = Date.now();
    while (Date.now() - start < timeout) {
        if (e && e.data) {
            return e;
        }
        await new Promise(resolve => setTimeout(resolve, interval));
    }
    return null;
};

// Promise handler for robust execution and error catching
Promise.resolve().then(async () => {

    // Wait for 'e' to be available
    const resolvedE = await waitForE();

    if (!resolvedE) {
        console.warn("Action: 'e' object was not available within timeout.");
        return;
    }

    // Now safe to access e.data
    if (!resolvedE.data?.date) {
        resolvedE.data.date = new Date();
    }

}).catch((err) => {
    console.error("Caught error in Action:", err);
});

